const messageText = $json.message?.text || "";
const chatId = $json.message?.chat?.id;

// Kullanıcı /analiz THYAO veya /analiz BTC yazdı mı?
if (messageText.toLowerCase().startsWith('/analiz')) {
  const parts = messageText.trim().split(/\s+/);
  const rawSymbol = parts[1] ? parts[1].toUpperCase() : null;

  if (rawSymbol) {
    // Yahoo Finance / Kripto sembol dönüştürme
    let yahooSymbol = rawSymbol;
    if (['BTC', 'ETH', 'XRP', 'SOL', 'EIGEN'].includes(rawSymbol)) {
      yahooSymbol = `${rawSymbol}-USD`;
    } else if (!rawSymbol.includes('.') && !rawSymbol.includes('-')) {
      yahooSymbol = `${rawSymbol}.IS`; // BİST hisseleri için .IS takısı
    }

    return [{
      json: {
        chat_id: chatId,
        symbol: rawSymbol,
        yahoo_symbol: yahooSymbol,
        valid: true
      }
    }];
  }
}

return [{
  json: {
    chat_id: chatId,
    valid: false,
    error_msg: "⚠️ Lütfen geçerli bir format yazın. Örnek: <code>/analiz THYAO</code> veya <code>/analiz BTC</code>"
  }
}];

