={{
  (() => {
    const chartData = $('HTTP Request').first().json?.chart?.result?.[0];
    const meta = chartData?.meta || {};
    const quotes = chartData?.indicators?.quote?.[0] || {};
    const closes = (quotes.close || []).filter(v => v !== null && v !== undefined);
    const volumes = (quotes.volume || []).filter(v => v !== null && v !== undefined);

    const calcSMA = (data, period) => {
      if (data.length < period) return "N/A";
      const slice = data.slice(-period);
      return (slice.reduce((a, b) => a + b, 0) / period).toFixed(2);
    };

    // ~1.200 Token'lık Tam Donanımlı Teknik Veri Seti
    const optimizedData = {
      symbol: meta.symbol,
      price: meta.regularMarketPrice,
      prevClose: meta.chartPreviousClose,
      high52: meta.fiftyTwoWeekHigh,
      low52: meta.fiftyTwoWeekLow,
      sma: {
        sma20: calcSMA(closes, 20),
        sma50: calcSMA(closes, 50),
        sma200: calcSMA(closes, 200)
      },
      volume: {
        last: volumes.slice(-1)[0] || "N/A",
        avg30: volumes.length >= 30 ? Math.round(volumes.slice(-30).reduce((a,b)=>a+b,0)/30) : "N/A"
      },
      last15Closes: closes.slice(-15).map(v => v.toFixed(2))
    };

    return {
      "model": "llama-3.3-70b-versatile",
      "messages": [
        {
          "role": "system",
          "content": "Sen Senior Quant Analistisin. Sana iletilen TEKNİK VERİ SETİ (SMA 20/50/200, Hacim, Son 15 Günlük Fiyatlar) ve TRADINGVIEW FİKİRLERİNİ sentezleyerek Telegram HTML formatında NİCEL ANALİZ RAPORU sunacaksın.\n\nANALİZ ADIMLARI:\n1. Fiyatın SMA20, SMA50 ve SMA200'e göre konumunu (Golden/Death Cross, destek/direnç) incele.\n2. Son hacim ile 30 günlük ortalama hacmi kıyaslayıp hacim gücünü belirt.\n3. TradingView analistlerinin gördüğü teknik formasyonları ekle.\n4. SADECE Telegram HTML etiketleri (<b>, <i>) kullan.\n\nÇIKTI FORMATI:\n🔍 <b>NİCEL ANALİZ RAPORU: VARLIK_ADI</b>\n───────────────\n💵 <b>Canlı Fiyat:</b> ...\n📈 <b>Hareketli Ortalamalar:</b> SMA20: ... | SMA50: ... | SMA200: ...\n📊 <b>Hacim Gücü:</b> ...\n🎯 <b>Kritik Destek & Direnç:</b> Destek: ... | Direnç: ...\n\n📊 <b>TRADINGVIEW TEKNİK GRAFİK HİSSİYATI</b>\n• [TradingView analist yorumları]\n\n🧠 <b>YAPAY ZEKA NİCEL STRATEJİSİ</b>\n<b>Tavsiye Kararı:</b> 🟢 GÜÇLÜ AL / 🟢 DİP ALIMI / 🟡 NÖTR-BEKLE / 🔴 SAT\n<b>Gerekçeli Not:</b> [SMA ortalamaları, trend ve TradingView verilerinin sentezine dayalı 2-3 cümlelik net yönlendirme]"
        },
        {
          "role": "user",
          "content": "TEKNİK VERİ:\n" + JSON.stringify(optimizedData) + "\n\nTRADINGVIEW FİKİRLERİ:\n" + ($json.tradingview_summary || "Özel TradingView fikri bulunamadı.")
        }
      ],
      "temperature": 0.2
    };
  })()
}}

