const items = $input.all();
let tvIdeas = "Bu varlık için anlık özel TradingView fikri bulunamadı.";

if (items && items.length > 0) {
  const selected = items.slice(0, 3);
  tvIdeas = selected.map((item, index) => {
    const title = item.json.title || '';
    const snippet = item.json.contentSnippet || item.json.content || '';
    const cleanSnippet = snippet.replace(/<[^>]*>?/gm, '').slice(0, 180); 
    return `${index + 1}. ${title}: ${cleanSnippet}...`;
  }).join('\n');
}

return [{
  json: {
    tradingview_summary: tvIdeas
  }
}];
